#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // Create reactive variables
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // Track recomputation count
    int recompute_count = 0;

    // Create calculation that depends on a and b
    auto sum_calc = reaction::calc([a, b, &recompute_count]() {
        recompute_count++;
        return a.get() + b.get();
    });

    // Perform non-batch updates
    a.set(nonBatchA);
    b.set(nonBatchB);

    int nonBatchCount = recompute_count;

    // Perform batch updates
    {
        reaction::Batch batch;
        a.set(batchA);
        b.set(batchB);
    }

    int batchCount = recompute_count;

    // Get the final sum
    int final_sum = sum_calc.get();

    return {final_sum, nonBatchCount, batchCount};
}

}  // namespace test_reaction

